from haystack import Pipeline, component
from vex import Guardrail, GuardrailResult
from typing import Any

@component
class VexPHIComponent:
    def __init__(self):
        self.phi_guardrail = Guardrail('healthcare-phi-v1')

    @component.output_types(rejected=bool, alert=str)
    def run(self, text: str) -> dict:
        result = self.phi_guardrail.run(text)
        if result.risk == 'high':
            return {'rejected': True, 'alert': 'PHI detected - blocking LLM access'}
        return {'rejected': False, 'alert': ''}

# Usage in pipeline
p = Pipeline()
p.add_component('vex_phi', VexPHIComponent())
p.connect('vex_phi.rejected', 'end')

from haystack.components.retrievers.in_memory import InMemoryEmbeddingRetriever
from vex import Guardrail

class VexRetriever:
    def __init__(self, retriever):
        self.retriever = retriever
        self.relevance_guard = Guardrail('medical-relevance-v1')

    def run(self, query: str, top_k: int = 5):
        docs = self.retriever.run(query=query, top_k=top_k)['documents']
        scored_docs = []
        for doc in docs:
            score = self.relevance_guard.run(f"Query: {query}\nDoc: {doc.content}")['score']
            if score > 0.7:
                scored_docs.append(doc)
        return {'documents': scored_docs}

# Integrate into Haystack pipeline
retriever = VexRetriever(InMemoryEmbeddingRetriever(document_store))

from haystack.components.generators import OpenAIGenerator
from vex import Guardrail

@component
class VexHallucinationCheck:
    def __init__(self):
        self.hallucination_guard = Guardrail('healthcare-hallucination-v1')

    @component.output_types(valid=str, risk_score=float, explanation=str)
    def run(self, generated_text: str, context_docs: list) -> dict:
        context = '\n'.join([doc.content for doc in context_docs])
        result = self.hallucination_guard.run({
            'response': generated_text,
            'context': context
        })
        return {
            'valid': generated_text if result.risk < 0.3 else '',
            'risk_score': result.risk,
            'explanation': result.explanation
        }

# Pipeline wiring
p.add_component('generator', OpenAIGenerator())
p.add_component('vex_hallucination', VexHallucinationCheck())
p.connect('generator', 'vex_hallucination.generated_text')
p.connect('retriever', 'vex_hallucination.context_docs')
